import{_ as e,o as t,c as r,a2 as s}from"./chunks/framework.DtwafDNl.js";const g=JSON.parse('{"title":"Troubleshooting","description":"","frontmatter":{},"headers":[],"relativePath":"troubleshooting/index.md","filePath":"troubleshooting/index.md"}'),n={name:"troubleshooting/index.md"};function a(i,o,l,d,c,u){return t(),r("div",null,[...o[0]||(o[0]=[s('<h1 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h1><p>Common issues and how to fix them when running Callytics.</p><h2 id="_1-ari-connection-refused" tabindex="-1">1. &quot;ARI Connection Refused&quot; <a class="header-anchor" href="#_1-ari-connection-refused" aria-label="Permalink to &quot;1. &quot;ARI Connection Refused&quot;&quot;">​</a></h2><p>If the Stasis service logs show <code>Connection Refused</code> to <code>http://127.0.0.1:8088</code>:</p><ul><li><strong>Check Asterisk:</strong> Run <code>docker compose logs asterisk</code> and look for <code>ari.conf</code> loading errors.</li><li><strong>Check ARI Credentials:</strong> Ensure <code>ARI_USER</code> and <code>ARI_PASS</code> in your <code>.env</code> match the entries in <code>asterisk/ari.conf</code>.</li><li><strong>Host Networking:</strong> Ensure <code>network_mode: host</code> is set for both <code>asterisk</code> and <code>stasis</code> in <code>docker-compose.yml</code>.</li></ul><h2 id="_2-no-audio-on-calls-one-way-audio" tabindex="-1">2. No Audio on Calls (One-way Audio) <a class="header-anchor" href="#_2-no-audio-on-calls-one-way-audio" aria-label="Permalink to &quot;2. No Audio on Calls (One-way Audio)&quot;">​</a></h2><p>Telephony audio (RTP) often fails due to NAT or firewall issues.</p><ul><li><strong>Port Ranges:</strong> Ensure UDP ports <code>10000-10100</code> are open on your host firewall.</li><li><strong>Local Address:</strong> In <code>asterisk/pjsip.conf</code>, check that your <code>local_net</code> and <code>external_media_address</code> are correctly configured if you are behind a public IP.</li><li><strong>SIP ALG:</strong> Many routers have a feature called &quot;SIP ALG&quot; that corrupts packets. Disable it if possible.</li></ul><h2 id="_3-ui-shows-internal-server-error" tabindex="-1">3. UI Shows &quot;Internal Server Error&quot; <a class="header-anchor" href="#_3-ui-shows-internal-server-error" aria-label="Permalink to &quot;3. UI Shows &quot;Internal Server Error&quot;&quot;">​</a></h2><ul><li><strong>Database Status:</strong> Ensure PostgreSQL is running and healthy: <code>docker compose ps</code>.</li><li><strong>Migrations:</strong> If you just upgraded, the database schema might be out of date. Check the <code>backend</code> logs for migration failures.</li><li><strong>Redis Port Conflict:</strong> Callytics uses <code>6380</code> for Redis. If another service is using that port, the backend will fail to start.</li></ul><h2 id="_4-sip-registration-fails" tabindex="-1">4. SIP Registration Fails <a class="header-anchor" href="#_4-sip-registration-fails" aria-label="Permalink to &quot;4. SIP Registration Fails&quot;">​</a></h2><ul><li><strong>Wrong Port:</strong> Ensure your softphone is connecting to port <code>5080</code>, not the standard <code>5060</code>.</li><li><strong>Firewall Blocked:</strong> If you failed login multiple times, the SIP Firewall might have blocked your IP. Check <strong>SYSTEM -&gt; Firewall -&gt; Blocked IPs</strong>.</li><li><strong>PJSIP Reload:</strong> After adding an extension, Asterisk needs a reload. In the UI, check <strong>DIAGNOSTICS -&gt; System Health</strong> to ensure ARI/AMI are <code>connected</code>.</li></ul>',12)])])}const f=e(n,[["render",a]]);export{g as __pageData,f as default};
